using MeAjudaAi.Shared.Database;
using MeAjudaAi.Modules.ServiceCatalogs.Application.Commands.Service;  using MeAjudaAi.Modules.ServiceCatalogs.Domain.Exceptions; using MeAjudaAi.Modules.ServiceCatalogs.Domain.ValueObjects; using MeAjudaAi.Shared.Commands; using MeAjudaAi.Shared.Exceptions; using MeAjudaAi.Contracts.Functional; using ServiceEntity = MeAjudaAi.Modules.ServiceCatalogs.Domain.Entities.Service; using ServiceCategoryEntity = MeAjudaAi.Modules.ServiceCatalogs.Domain.Entities.ServiceCategory;  namespace MeAjudaAi.Modules.ServiceCatalogs.Application.Handlers.Commands.Service;  public sealed class ChangeServiceCategoryCommandHandler(     IUnitOfWork uow)     : ICommandHandler<ChangeServiceCategoryCommand, Result> {     public async Task<Result> HandleAsync(ChangeServiceCategoryCommand request, CancellationToken cancellationToken = default)     {         try         {             if (request.ServiceId == Guid.Empty)                 return Result.Failure("O ID do serviço não pode ser vazio.");              if (request.NewCategoryId == Guid.Empty)                 return Result.Failure("O ID da nova categoria não pode ser vazio.");              var serviceRepository = uow.GetRepository<ServiceEntity, ServiceId>();             var categoryRepository = uow.GetRepository<ServiceCategoryEntity, ServiceCategoryId>();              var service = await serviceRepository.TryFindAsync(ServiceId.From(request.ServiceId), cancellationToken);              if (service is null)                 return Result.Failure(Error.NotFound($"Serviço com ID '{request.ServiceId}' não encontrado."));              var newCategory = await categoryRepository.TryFindAsync(ServiceCategoryId.From(request.NewCategoryId), cancellationToken);              if (newCategory is null)                 throw new UnprocessableEntityException(                     $"Categoria com ID '{request.NewCategoryId}' não encontrada.",                     "ServiceCategory");              if (!newCategory.IsActive)                 throw new UnprocessableEntityException(                     "Não é possível mover serviço para categoria inativa.",                     "ServiceCategory");              service.ChangeCategory(newCategory.Id);              await uow.SaveChangesAsync(cancellationToken);              return Result.Success();         }         catch (CatalogDomainException ex)         {             return Result.Failure(ex.Message);         }     } }
